example.code:
using ByteForge.Toolkit;

// Configure file transfer connection
var config = new FileTransferConfig
{
    Protocol = TransferProtocol.SFTP,
    HostName = "ftp.example.com",
    UserName = "user123",
    Password = "password123",
    Port = 22,
    Timeout = TimeSpan.FromSeconds(30),
    EnableCompression = true,
    TransferMode = TransferMode.Binary
};

var client = new FileTransferClient();

// Subscribe to progress events
client.ProgressChanged += (sender, progress) =>
{
    Console.WriteLine($"Progress: {progress.FileName}");
    Console.WriteLine($"  {progress.PercentComplete:P1} complete");
    Console.WriteLine($"  {progress.TransferredBytes:N0}/{progress.TotalBytes:N0} bytes");
    Console.WriteLine($"  Speed: {progress.Speed:N0} B/s");

    if (progress.EstimatedTimeRemaining > TimeSpan.Zero)
    {
        Console.WriteLine($"  ETA: {progress.EstimatedTimeRemaining:hh\\:mm\\:ss}");
    }
    Console.WriteLine();
};

client.TransferCompleted += (sender, result) =>
{
    if (result.IsSuccess)
    {
        Console.WriteLine($"✓ Transfer completed in {result.Duration.TotalSeconds:F1}s");
        Console.WriteLine($"  Files transferred: {result.TransferedFiles.Count}");
    }
    else
    {
        Console.WriteLine($"✗ Transfer failed: {result.ErrorMessage}");
        Console.WriteLine($"  Failed files: {result.FailedFiles.Count}");
    }
};

try
{
    // Connect to remote server
    Console.WriteLine("Connecting to remote server...");
    client.Connect(config);
    Console.WriteLine($"Connected: {client.IsConnected}");

    // Upload a single file
    Console.WriteLine("Uploading file...");
    var uploadResult = await client.UploadAsync(
        localPath: @"C:\Data\report.pdf",
        remotePath: "/uploads/reports/"
    );

    if (uploadResult.IsSuccess)
    {
        Console.WriteLine("Upload successful!");

        foreach (var file in uploadResult.TransferedFiles)
        {
            Console.WriteLine($"  Uploaded: {file.FileName} ({file.FileSize:N0} bytes)");
        }
    }

    // Download a file
    Console.WriteLine("Downloading file...");
    var downloadResult = await client.DownloadAsync(
        remotePath: "/exports/data.csv",
        localPath: @"C:\Downloads\"
    );

    if (downloadResult.IsSuccess)
    {
        Console.WriteLine("Download successful!");

        foreach (var file in downloadResult.TransferedFiles)
        {
            Console.WriteLine($"  Downloaded: {file.FileName} to {file.DestinationPath}");
        }
    }
    else
    {
        Console.WriteLine($"Download failed: {downloadResult.ErrorMessage}");
    }
}
catch (FileTransferException ex)
{
    Console.WriteLine($"Transfer error: {ex.Message} (Code: {ex.ErrorCode})");
}
catch (Exception ex)
{
    Console.WriteLine($"Unexpected error: {ex.Message}");
}
finally
{
    if (client.IsConnected)
    {
        client.Disconnect();
        Console.WriteLine("Disconnected from server");
    }
}

// Batch upload multiple files
var client = new FileTransferClient();
var config = new FileTransferConfig
{
    Protocol = TransferProtocol.SFTP,
    HostName = "server.example.com",
    UserName = "batchuser",
    Password = "batchpass",
    EnableCompression = true
};

try
{
    client.Connect(config);

    // Prepare batch upload items
    var uploadItems = new List<FileTransferItem>
    {
        new FileTransferItem
        {
            SourcePath = @"C:\Data\file1.csv",
            DestinationPath = "/uploads/batch/",
            Overwrite = true
        },
        new FileTransferItem
        {
            SourcePath = @"C:\Data\file2.xlsx",
            DestinationPath = "/uploads/batch/",
            Overwrite = false
        },
        new FileTransferItem
        {
            SourcePath = @"C:\Data\archive.zip",
            DestinationPath = "/uploads/archives/",
            Overwrite = true
        }
    };

    Console.WriteLine($"Starting batch upload of {uploadItems.Count} files...");

    // Track overall progress
    int completedFiles = 0;
    client.ProgressChanged += (sender, progress) =>
    {
        // Update progress for current file
        Console.Write($"\r[{completedFiles + 1}/{uploadItems.Count}] {progress.FileName}: {progress.PercentComplete:P0}");
    };

    client.TransferCompleted += (sender, result) =>
    {
        completedFiles++;
        Console.WriteLine(); // New line after progress
    };

    var batchResult = await client.UploadBatchAsync(uploadItems);

    Console.WriteLine("\nBatch Upload Summary:");
    Console.WriteLine($"  Total files: {uploadItems.Count}");
    Console.WriteLine($"  Successful: {batchResult.TransferedFiles.Count}");
    Console.WriteLine($"  Failed: {batchResult.FailedFiles.Count}");
    Console.WriteLine($"  Duration: {batchResult.Duration.TotalMinutes:F1} minutes");

    if (batchResult.FailedFiles.Any())
    {
        Console.WriteLine("\nFailed files:");
        foreach (var failed in batchResult.FailedFiles)
        {
            Console.WriteLine($"  ✗ {failed.FileName}: {batchResult.ErrorMessage}");
        }
    }

    if (batchResult.TransferedFiles.Any())
    {
        Console.WriteLine("\nSuccessful transfers:");
        foreach (var success in batchResult.TransferedFiles)
        {
            Console.WriteLine($"  ✓ {success.FileName} -> {success.DestinationPath}");
        }
    }

    // Batch download example
    var downloadItems = new List<FileTransferItem>
    {
        new FileTransferItem
        {
            SourcePath = "/exports/daily_report.pdf",
            DestinationPath = @"C:\Downloads\Reports\",
            Overwrite = true
        },
        new FileTransferItem
        {
            SourcePath = "/exports/weekly_stats.xlsx",
            DestinationPath = @"C:\Downloads\Reports\",
            Overwrite = true
        }
    };

    Console.WriteLine($"\nStarting batch download of {downloadItems.Count} files...");
    var downloadResult = await client.DownloadBatchAsync(downloadItems);

    Console.WriteLine("Batch Download Summary:");
    Console.WriteLine($"  Successful: {downloadResult.TransferedFiles.Count}");
    Console.WriteLine($"  Failed: {downloadResult.FailedFiles.Count}");

    // Calculate total bytes transferred
    long totalBytes = downloadResult.TransferedFiles.Sum(f => f.FileSize);
    Console.WriteLine($"  Total downloaded: {totalBytes:N0} bytes ({totalBytes / 1024.0 / 1024.0:F1} MB)");
}
finally
{
    client.Disconnect();
}

// Advanced file transfer operations with directory management
var client = new FileTransferClient();
var config = new FileTransferConfig
{
    Protocol = TransferProtocol.SFTP,
    HostName = "fileserver.company.com",
    UserName = "admin",
    Password = "adminpass123"
};

try
{
    client.Connect(config);

    // List remote directory contents
    Console.WriteLine("Listing remote directory contents...");
    var remoteDir = await client.ListDirectoryAsync("/data/uploads/");

    Console.WriteLine($"Directory: {remoteDir.FullPath}");
    Console.WriteLine($"Last modified: {remoteDir.LastModified:yyyy-MM-dd HH:mm:ss}");
    Console.WriteLine();

    // Display subdirectories
    if (remoteDir.SubDirectories.Any())
    {
        Console.WriteLine("Subdirectories:");
        foreach (var subDir in remoteDir.SubDirectories)
        {
            Console.WriteLine($"  📁 {subDir.DirectoryName}/ ({subDir.LastModified:yyyy-MM-dd})");
        }
        Console.WriteLine();
    }

    // Display files
    if (remoteDir.Files.Any())
    {
        Console.WriteLine("Files:");
        foreach (var file in remoteDir.Files.OrderByDescending(f => f.LastModified))
        {
            string sizeDisplay = FormatFileSize(file.FileSize);
            string typeIcon = GetFileTypeIcon(file.FileName);

            Console.WriteLine($"  {typeIcon} {file.FileName}");
            Console.WriteLine($"    Size: {sizeDisplay}");
            Console.WriteLine($"    Modified: {file.LastModified:yyyy-MM-dd HH:mm:ss}");
            Console.WriteLine($"    Permissions: {file.Permissions}");

            if (file.IsSymLink)
            {
                Console.WriteLine($"    → Symbolic link");
            }
            Console.WriteLine();
        }
    }

    // Download files modified in the last 7 days
    var recentFiles = remoteDir.Files
        .Where(f => f.LastModified > DateTime.Now.AddDays(-7))
        .ToList();

    if (recentFiles.Any())
    {
        Console.WriteLine($"Found {recentFiles.Count} files modified in the last 7 days");

        var downloadItems = recentFiles.Select(f => new FileTransferItem
        {
            SourcePath = f.FullPath,
            DestinationPath = @"C:\Downloads\Recent\",
            FileName = f.FileName,
            FileSize = f.FileSize,
            LastModified = f.LastModified,
            Overwrite = false
        }).ToList();

        // Create local directory if it doesn't exist
        Directory.CreateDirectory(@"C:\Downloads\Recent");

        var downloadResult = await client.DownloadBatchAsync(downloadItems);

        Console.WriteLine($"Downloaded {downloadResult.TransferedFiles.Count} recent files");
    }

    // Check for large files (> 100 MB)
    var largeFiles = remoteDir.Files
        .Where(f => f.FileSize > 100 * 1024 * 1024)
        .OrderByDescending(f => f.FileSize)
        .ToList();

    if (largeFiles.Any())
    {
        Console.WriteLine("Large files detected (> 100 MB):");
        foreach (var file in largeFiles)
        {
            Console.WriteLine($"  ⚠ {file.FileName}: {FormatFileSize(file.FileSize)}");
        }
    }

    // Recursive directory listing
    await ListDirectoryRecursive(client, "/data/", maxDepth: 3);
}
finally
{
    client.Disconnect();
}

async Task ListDirectoryRecursive(FileTransferClient client, string path, int maxDepth, int currentDepth = 0)
{
    if (currentDepth >= maxDepth) return;

    try
    {
        var dir = await client.ListDirectoryAsync(path);
        string indent = new string(' ', currentDepth * 2);

        Console.WriteLine($"{indent}📁 {dir.DirectoryName}/");

        // List files in current directory
        foreach (var file in dir.Files.Take(5)) // Limit to first 5 files
        {
            Console.WriteLine($"{indent}  📄 {file.FileName} ({FormatFileSize(file.FileSize)})");
        }

        if (dir.Files.Count > 5)
        {
            Console.WriteLine($"{indent}  ... and {dir.Files.Count - 5} more files");
        }

        // Recurse into subdirectories
        foreach (var subDir in dir.SubDirectories.Take(3)) // Limit recursion
        {
            await ListDirectoryRecursive(client, subDir.FullPath, maxDepth, currentDepth + 1);
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"{new string(' ', currentDepth * 2)}❌ Error listing {path}: {ex.Message}");
    }
}

string FormatFileSize(long bytes)
{
    string[] suffixes = { "B", "KB", "MB", "GB", "TB" };
    int counter = 0;
    decimal number = bytes;

    while (Math.Round(number / 1024) >= 1)
    {
        number /= 1024;
        counter++;
    }

    return $"{number:N1} {suffixes[counter]}";
}

string GetFileTypeIcon(string fileName)
{
    string extension = Path.GetExtension(fileName).ToLower();

    return extension switch
    {
        ".pdf" => "📄",
        ".doc" or ".docx" => "📝",
        ".xls" or ".xlsx" => "📊",
        ".txt" => "📋",
        ".csv" => "📈",
        ".zip" or ".rar" or ".7z" => "📦",
        ".jpg" or ".png" or ".gif" => "🖼️",
        ".mp4" or ".avi" or ".mov" => "🎥",
        ".mp3" or ".wav" or ".flac" => "🎵",
        ".exe" or ".msi" => "⚙️",
        ".sql" => "🗃️",
        _ => "📄"
    };
}

using ByteForge.Toolkit;

// SFTP Configuration (recommended for security)
var sftpConfig = new FileTransferConfig
{
    Protocol = TransferProtocol.SFTP,
    HostName = "secure.example.com",
    Port = 22,  // Standard SFTP port
    UserName = "secureuser",
    Password = "securepassword",
    Timeout = TimeSpan.FromMinutes(5),
    EnableCompression = true,
    TransferMode = TransferMode.Binary,

    // Advanced SFTP settings
    EnableResume = true,  // Resume interrupted transfers
    VerifyHostKey = true, // Verify server host key
    CompressionLevel = 6  // 1-9, higher = more compression but slower
};

// FTP Configuration (legacy support)
var ftpConfig = new FileTransferConfig
{
    Protocol = TransferProtocol.FTP,
    HostName = "ftp.legacy-system.com",
    Port = 21,  // Standard FTP port
    UserName = "ftpuser",
    Password = "ftppassword",
    Timeout = TimeSpan.FromSeconds(30),
    TransferMode = TransferMode.Binary,
    PassiveMode = true  // Use passive FTP mode (recommended for firewalls)
};

// FTPS Configuration (FTP over SSL)
var ftpsConfig = new FileTransferConfig
{
    Protocol = TransferProtocol.FTPS,
    HostName = "ftps.secure-host.com",
    Port = 990,  // Implicit FTPS port (explicit FTPS uses 21)
    UserName = "ssluser",
    Password = "sslpassword",
    Timeout = TimeSpan.FromMinutes(2),
    TransferMode = TransferMode.Binary,

    // SSL/TLS settings
    SslMode = FtpSslMode.Implicit,  // or Explicit
    ValidateCertificate = true,
    ClientCertificatePath = @"C:\Certs\client.pfx",
    ClientCertificatePassword = "certpass"
};

// SCP Configuration (secure copy)
var scpConfig = new FileTransferConfig
{
    Protocol = TransferProtocol.SCP,
    HostName = "scp-server.example.com",
    Port = 22,
    UserName = "scpuser",
    Password = "scppassword",
    Timeout = TimeSpan.FromMinutes(10),  // Longer timeout for large files
    EnableCompression = true
};

// WebDAV Configuration
var webdavConfig = new FileTransferConfig
{
    Protocol = TransferProtocol.WebDAV,
    HostName = "webdav.cloud-provider.com",
    Port = 443,  // HTTPS port
    UserName = "clouduser",
    Password = "cloudtoken",
    Timeout = TimeSpan.FromMinutes(15),
    UseHttps = true,

    // WebDAV specific settings
    BaseUrl = "/webdav/",
    ChunkSize = 1024 * 1024 * 5,  // 5 MB chunks for large files
    MaxRetries = 3
};

// Configuration with key-based authentication (SFTP/SCP)
var keyAuthConfig = new FileTransferConfig
{
    Protocol = TransferProtocol.SFTP,
    HostName = "key-auth-server.com",
    UserName = "keyuser",

    // Use private key instead of password
    PrivateKeyPath = @"C:\SSH\private_key.openssh",
    PrivateKeyPassword = "keypassphrase",  // If key is password-protected

    Timeout = TimeSpan.FromMinutes(3),
    EnableCompression = true
};

// Test different configurations
var configurations = new Dictionary<string, FileTransferConfig>
{
    { "SFTP", sftpConfig },
    { "FTP", ftpConfig },
    { "FTPS", ftpsConfig },
    { "SCP", scpConfig },
    { "WebDAV", webdavConfig },
    { "Key-Auth", keyAuthConfig }
};

foreach (var configPair in configurations)
{
    string name = configPair.Key;
    var config = configPair.Value;

    Console.WriteLine($"Testing {name} configuration:");
    Console.WriteLine($"  Protocol: {config.Protocol}");
    Console.WriteLine($"  Host: {config.HostName}:{config.Port}");
    Console.WriteLine($"  User: {config.UserName}");
    Console.WriteLine($"  Timeout: {config.Timeout.TotalSeconds}s");
    Console.WriteLine($"  Compression: {config.EnableCompression}");

    var client = new FileTransferClient();

    try
    {
        // Test connection
        using (var timeoutCts = new CancellationTokenSource(config.Timeout))
        {
            client.Connect(config);

            if (client.IsConnected)
            {
                Console.WriteLine($"  ✓ Connection successful");

                // Test a simple operation (list root directory)
                try
                {
                    var rootDir = await client.ListDirectoryAsync("/");
                    Console.WriteLine($"  ✓ Directory listing successful ({rootDir.Files.Count + rootDir.SubDirectories.Count} items)");
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"  ⚠ Directory listing failed: {ex.Message}");
                }
            }
            else
            {
                Console.WriteLine($"  ✗ Connection failed");
            }
        }
    }
    catch (FileTransferException ex)
    {
        Console.WriteLine($"  ✗ Connection error: {ex.Message} (Code: {ex.ErrorCode})");
    }
    catch (TimeoutException)
    {
        Console.WriteLine($"  ✗ Connection timeout after {config.Timeout.TotalSeconds}s");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"  ✗ Unexpected error: {ex.Message}");
    }
    finally
    {
        if (client.IsConnected)
        {
            client.Disconnect();
        }
    }

    Console.WriteLine();
}

// Save configurations to file for reuse
SaveConfigurationsToFile(configurations);

void SaveConfigurationsToFile(Dictionary<string, FileTransferConfig> configs)
{
    var configData = new
    {
        Configurations = configs.Select(kvp => new
        {
            Name = kvp.Key,
            Protocol = kvp.Value.Protocol.ToString(),
            HostName = kvp.Value.HostName,
            Port = kvp.Value.Port,
            UserName = kvp.Value.UserName,
            // Don't save passwords in plain text in real applications
            TimeoutSeconds = kvp.Value.Timeout.TotalSeconds,
            EnableCompression = kvp.Value.EnableCompression,
            TransferMode = kvp.Value.TransferMode.ToString()
        }).ToList(),
        CreatedAt = DateTime.Now
    };

    string json = System.Text.Json.JsonSerializer.Serialize(configData, new JsonSerializerOptions 
    { 
        WriteIndented = true 
    });

    File.WriteAllText("transfer_configs.json", json);
    Console.WriteLine("Configurations saved to transfer_configs.json");
}

// Advanced progress tracking with statistics and UI updates
public class TransferProgressMonitor
{
    private readonly List<ProgressSnapshot> _progressHistory;
    private readonly Timer _statsTimer;
    private DateTime _transferStartTime;
    private long _lastBytesTransferred;
    private DateTime _lastUpdateTime;

    public TransferProgressMonitor()
    {
        _progressHistory = new List<ProgressSnapshot>();
        _statsTimer = new Timer(DisplayStatistics, null, Timeout.Infinite, Timeout.Infinite);
    }

    public void StartMonitoring(FileTransferClient client)
    {
        _transferStartTime = DateTime.Now;
        _lastUpdateTime = _transferStartTime;
        _progressHistory.Clear();

        client.ProgressChanged += OnProgressChanged;
        client.TransferCompleted += OnTransferCompleted;

        // Update statistics every 2 seconds
        _statsTimer.Change(TimeSpan.FromSeconds(2), TimeSpan.FromSeconds(2));
    }

    private void OnProgressChanged(object sender, FileTransferProgress progress)
    {
        // Record progress snapshot
        var snapshot = new ProgressSnapshot
        {
            Timestamp = DateTime.Now,
            FileName = progress.FileName,
            TotalBytes = progress.TotalBytes,
            TransferredBytes = progress.TransferredBytes,
            PercentComplete = progress.PercentComplete,
            Speed = progress.Speed,
            ElapsedTime = progress.ElapsedTime,
            EstimatedTimeRemaining = progress.EstimatedTimeRemaining
        };

        _progressHistory.Add(snapshot);

        // Keep only last 100 snapshots to manage memory
        if (_progressHistory.Count > 100)
        {
            _progressHistory.RemoveAt(0);
        }

        // Calculate instantaneous speed
        var now = DateTime.Now;
        var timeDiff = (now - _lastUpdateTime).TotalSeconds;

        if (timeDiff >= 1.0) // Update every second
        {
            var bytesDiff = progress.TransferredBytes - _lastBytesTransferred;
            var instantSpeed = timeDiff > 0 ? bytesDiff / timeDiff : 0;

            // Display progress with enhanced information
            Console.Clear();
            Console.WriteLine("=== File Transfer Progress ===");
            Console.WriteLine($"File: {progress.FileName}");
            Console.WriteLine($"Progress: {progress.PercentComplete:P1}");
            Console.WriteLine($"Size: {FormatBytes(progress.TransferredBytes)} / {FormatBytes(progress.TotalBytes)}");
            Console.WriteLine($"Current Speed: {FormatBytes((long)instantSpeed)}/s");
            Console.WriteLine($"Average Speed: {FormatBytes((long)progress.Speed)}/s");
            Console.WriteLine($"Elapsed: {FormatTime(progress.ElapsedTime)}");
            Console.WriteLine($"Remaining: {FormatTime(progress.EstimatedTimeRemaining)}");
            Console.WriteLine();

            // Draw progress bar
            DrawProgressBar(progress.PercentComplete, 50);
            Console.WriteLine();

            // Show speed graph (last 10 data points)
            ShowSpeedGraph();

            _lastBytesTransferred = progress.TransferredBytes;
            _lastUpdateTime = now;
        }
    }

    private void OnTransferCompleted(object sender, FileTransferResult result)
    {
        _statsTimer.Change(Timeout.Infinite, Timeout.Infinite);

        Console.Clear();
        Console.WriteLine("=== Transfer Complete ===");

        if (result.IsSuccess)
        {
            var duration = result.Duration;
            var totalBytes = result.TransferedFiles.Sum(f => f.FileSize);
            var averageSpeed = totalBytes / duration.TotalSeconds;

            Console.WriteLine($"✓ Transfer successful!");
            Console.WriteLine($"Files transferred: {result.TransferedFiles.Count}");
            Console.WriteLine($"Total size: {FormatBytes(totalBytes)}");
            Console.WriteLine($"Duration: {FormatTime(duration)}");
            Console.WriteLine($"Average speed: {FormatBytes((long)averageSpeed)}/s");

            // Show final statistics
            ShowFinalStatistics();
        }
        else
        {
            Console.WriteLine($"✗ Transfer failed: {result.ErrorMessage}");
            Console.WriteLine($"Failed files: {result.FailedFiles.Count}");
        }
    }

    private void DrawProgressBar(double percentage, int width)
    {
        int completed = (int)(percentage * width);
        int remaining = width - completed;

        Console.Write("[");
        Console.Write(new string('█', completed));
        Console.Write(new string('░', remaining));
        Console.Write($"] {percentage:P1}");
    }

    private void ShowSpeedGraph()
    {
        if (_progressHistory.Count < 2) return;

        var recentSpeeds = _progressHistory
            .TakeLast(10)
            .Select(s => s.Speed)
            .ToList();

        if (!recentSpeeds.Any()) return;

        var maxSpeed = recentSpeeds.Max();
        var minSpeed = recentSpeeds.Min();

        Console.WriteLine("Speed History (last 10 samples):");

        for (int i = 0; i < recentSpeeds.Count; i++)
        {
            var speed = recentSpeeds[i];
            var percentage = maxSpeed > 0 ? speed / maxSpeed : 0;
            var barLength = (int)(percentage * 20);

            Console.WriteLine($"  {i + 1:D2}: {new string('▓', barLength),-20} {FormatBytes((long)speed)}/s");
        }
    }

    private void ShowFinalStatistics()
    {
        if (!_progressHistory.Any()) return;

        var speeds = _progressHistory.Select(s => s.Speed).ToList();
        var avgSpeed = speeds.Average();
        var maxSpeed = speeds.Max();
        var minSpeed = speeds.Where(s => s > 0).DefaultIfEmpty(0).Min();

        Console.WriteLine();
        Console.WriteLine("Transfer Statistics:");
        Console.WriteLine($"  Average Speed: {FormatBytes((long)avgSpeed)}/s");
        Console.WriteLine($"  Peak Speed: {FormatBytes((long)maxSpeed)}/s");
        Console.WriteLine($"  Minimum Speed: {FormatBytes((long)minSpeed)}/s");
        Console.WriteLine($"  Speed Variation: {(maxSpeed - minSpeed) / avgSpeed * 100:F1}%");
        Console.WriteLine($"  Samples Recorded: {_progressHistory.Count}");
    }

    private void DisplayStatistics(object state)
    {
        // This would update a separate statistics window or log
        if (_progressHistory.Any())
        {
            var latest = _progressHistory.Last();
            var logMessage = $"[{latest.Timestamp:HH:mm:ss}] {latest.FileName}: " +
                           $"{latest.PercentComplete:P1} at {FormatBytes((long)latest.Speed)}/s";

            // Log to file or send to monitoring system
            File.AppendAllText("transfer_log.txt", logMessage + Environment.NewLine);
        }
    }

    private string FormatBytes(long bytes)
    {
        string[] suffixes = { "B", "KB", "MB", "GB", "TB" };
        int counter = 0;
        decimal number = bytes;

        while (Math.Round(number / 1024) >= 1)
        {
            number /= 1024;
            counter++;
        }

        return $"{number:N1} {suffixes[counter]}";
    }

    private string FormatTime(TimeSpan time)
    {
        if (time.TotalDays >= 1)
            return $"{time.Days}d {time.Hours:D2}:{time.Minutes:D2}:{time.Seconds:D2}";
        else if (time.TotalHours >= 1)
            return $"{time.Hours:D2}:{time.Minutes:D2}:{time.Seconds:D2}";
        else
            return $"{time.Minutes:D2}:{time.Seconds:D2}";
    }
}

public class ProgressSnapshot
{
    public DateTime Timestamp { get; set; }
    public string FileName { get; set; }
    public long TotalBytes { get; set; }
    public long TransferredBytes { get; set; }
    public double PercentComplete { get; set; }
    public double Speed { get; set; }
    public TimeSpan ElapsedTime { get; set; }
    public TimeSpan EstimatedTimeRemaining { get; set; }
}

